import React from 'react';

// 1. THIS IS YOUR DATABASE - ALL MENU ITEMS GO HERE
const fullMenu = [
  { id: 1, category: "Small Chops", name: "Starter Pack", price: "15,000", description: "Samosa, Springroll, Mosa & Chicken" },
  { id: 2, category: "Small Chops", name: "Premium Pack", price: "25,000", description: "Full variety with Gizzard and Puff-puff" },
  { id: 3, category: "Small Chops", name: "Executive Platter", price: "150,000", description: "Large event platter for corporate groups" },
  { id: 4, category: "Custom", name: "Customized Platter", price: "Flexible", description: "Built to your taste and budget" },
  { id: 5, category: "Office Lunch", name: "Executive Lunch Pack", price: "6,500", description: "Signature Jollof, Protein, and Salad" }
];

const Menu = () => {
  return (
    <section style={{ backgroundColor: '#0A0A0A', padding: '60px 20px' }}>
      
      {/* Small Chops Section */}
      <h2 style={{ textAlign: 'center', color: '#D4AF37', textTransform: 'uppercase', letterSpacing: '3px' }}>Our Collections</h2>
      <p style={{ textAlign: 'center', color: '#E07A5F', marginBottom: '50px' }}>Àmí by T: Taste and Style</p>
      
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', 
        gap: '30px', 
        maxWidth: '1200px', 
        margin: '0 auto' 
      }}>
        {fullMenu.map((item) => (
          <div key={item.id} style={{ 
            border: '1px solid #1A1A1A', 
            borderRadius: '15px', 
            background: '#111', 
            padding: '30px',
            transition: '0.3s',
            boxShadow: item.category === 'Custom' ? '0 0 15px rgba(212, 175, 55, 0.2)' : 'none'
          }}>
            <span style={{ fontSize: '0.7rem', color: '#E07A5F', textTransform: 'uppercase' }}>{item.category}</span>
            <h3 style={{ color: '#D4AF37', margin: '10px 0', fontSize: '1.5rem' }}>{item.name}</h3>
            <p style={{ color: '#888', fontSize: '0.9rem', marginBottom: '20px' }}>{item.description}</p>
            <p style={{ color: '#FFF', fontSize: '1.3rem', fontWeight: 'bold' }}>
              {item.price === 'Flexible' ? 'Contact for Quote' : `₦${item.price}`}
            </p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Menu;
